10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const ALIKE_BUNDLE_DISCOUNT = 15;
13	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	
18	function ceilToWholeGold(amount: number): number {
19	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
20	}
21	
22	function basePremiumFor(itemType: string): number {
23	  return BASE_PREMIUMS[itemType] ?? 0;
24	}
25	
26	function itemPremium(item: { type: string; cursed?: boolean; enchantment?: number }): number {
27	  const base = basePremiumFor(item.type);
28	  if (item.cursed) return base * CURSED_SURCHARGE_MULTIPLIER;
29	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
30	    return base * HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER;
31	  return base;
32	}
33	
34	function countOfType(items: Array<{ type: string }>, itemType: string): number {
35	  return items.filter((item) => item.type === itemType).length;
36	}
37	
38	function alikeBundleDiscount(items: Array<{ type: string }>): number {
39	  const bundleCount = COMPONENT_TYPES.reduce(
40	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
41	    0,
42	  );
43	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
44	}
45	
46	export function quote(input: {
47	  items: Array<{ type: string; cursed?: boolean; enchantment?: number }>;
48	}): number {
49	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
50	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
51	  const total = itemsTotal * INITIAL_ASSESSMENT_MULTIPLIER + PROCESSING_FEE;
52	  return ceilToWholeGold(total);
53	}
54	
55	export function claim(_input: unknown): number {
56	  return undefined as unknown as number;
57	}
